class Solution {
public:
    int makeTheIntegerZero(int num1, int num2) {
        if (num1 < num2) return -1;
        int ops = 0;
        while (num1 > 0) {
            int i = (num1 - num2 - 1) / 2;
            if (i < 0) i = 0;
            num1 -= (2 * i + num2);
            ops += i;
        }
        return ops;
    }
};
```

